INSERT INTO `tbl_cms_about` (`id`, `about_text`, `mission_text`, `vision_text`, `core_responsibilities`) VALUES
(1, 'Under the Research Development and Evaluation Center (RDEC), the SDMU collects, manages, and analyzes data within the University.', 'SDMU is committed to providing appropriate statistical information and analyses while ensuring that the R&D data of the University are properly stored and managed.', 'SDMU aspires to become the leading hub of statistical expertise and data integrity within Western Mindanao State University.', 'Collects pertinent data that includes demographic profile of the teaching and nonteaching personnel within the University.\r\nPresents summary of data with conclusion and recommendations. \r\nHandles data processing, storage, and retrieval, as well as the production of hard-copy information. \r\nManage database that includes updating and data screening\r\nPerforms statistical computations and analyses for research projects. ');
