(1, 'SDMU Launches New Demographic Dashboard', 'The office has officially rolled out the new interactive dashboard for teaching and non-teaching personnel data. TEST', 'NOT WORKING', 'uploads/cms/news_1777195098_serdac.png', '2026-10-12'),
(2, 'WMSU Researchers Benefit from Advanced Statistical Tools', 'A recent seminar hosted by SDMU showcased advanced statistical computation methods for ongoing R&D projects.', '<p>Full details about the seminar go here.</p>', 'uploads/cms/news_1777195895_Screenshot (76).png', '2026-09-28'),
(3, 'Annual Data Integrity Audit Completed', 'Ensuring the highest standards, the SDMU has successfully concluded the annual screening of the university database.', '<p>Full details about the data integrity audit go here.</p>', 'img/research_center.jpg', '2026-09-10');
